const jwt = require('jsonwebtoken');
const express = require('express');

// Create an Express app
const app = express();

// Set up JWT authentication middleware
app.use(jwt({ secret: 'YOUR_SECRET_KEY', algorithms: ['HS256'] }));

// Define a route for the API endpoint
app.get('/api/users', (req, res) => {
  // Verify the token signature and extract user information
  const decoded = jwt.verify(req.headers['authorization'], 'YOUR_SECRET_KEY');
  const userId = decoded.userId;
  const username = decoded.username;

  // Perform any necessary validation on the user information
  if (userId === undefined || username === undefined) {
    res.status(401).json({ message: 'Invalid token' });
    return;
  }

  // Query the database to retrieve the user information
  const user = await User.findById(userId);

  // Return the user information in a JSON object
  res.json({
    id: userId,
    username: username,
    email: user.email,
  });
});